/**
 * @summary Get legal moves for a square in a multiplayer game
 */
export const getGetGameLegalMovesUrl = (
  id: string,
  params: GetGameLegalMovesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/games/${id}/legal-moves?${stringifiedParams}`
    : `/api/games/${id}/legal-moves`;
};

export const getGameLegalMoves = async (
  id: string,
  params: GetGameLegalMovesParams,
  options?: RequestInit,
): Promise<LegalMovesResponse> => {
  return customFetch<LegalMovesResponse>(getGetGameLegalMovesUrl(id, params), {
    ...options,
    method: "GET",
  });
};

export const getGetGameLegalMovesQueryKey = (
  id: string,
  params?: GetGameLegalMovesParams,
) => {
  return [`/api/games/${id}/legal-moves`, ...(params ? [params] : [])] as const;
};

export const getGetGameLegalMovesQueryOptions = <
  TData = Awaited<ReturnType<typeof getGameLegalMoves>>,
  TError = ErrorType<unknown>,
>(
  id: string,
  params: GetGameLegalMovesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getGameLegalMoves>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetGameLegalMovesQueryKey(id, params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getGameLegalMoves>>
  > = ({ signal }) =>
    getGameLegalMoves(id, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getGameLegalMoves>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetGameLegalMovesQueryResult = NonNullable<
  Awaited<ReturnType<typeof getGameLegalMoves>>
>;
export type GetGameLegalMovesQueryError = ErrorType<unknown>;

/**
 * @summary Get legal moves for a square in a multiplayer game
 */

export function useGetGameLegalMoves<
  TData = Awaited<ReturnType<typeof getGameLegalMoves>>,
  TError = ErrorType<unknown>,
>(
  id: string,
  params: GetGameLegalMovesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getGameLegalMoves>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetGameLegalMovesQueryOptions(id, params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
